const CoachScreen = ({level,participantName,savedState,onSave,onReset}) => {
  const [messages,      setMessages]      = useState([]);
  const [input,         setInput]         = useState("");
  const [typing,        setTyping]        = useState(false);
  const [legacy,        setLegacy]        = useState("");
  const [catalyst,      setCatalyst]      = useState("");
  const [currentModule, setCurrentModule] = useState(1);
  const [journeyOpen,   setJourneyOpen]   = useState(false);
  const [panelOpen,     setPanelOpen]     = useState(false);
  const [panelDot,      setPanelDot]      = useState(false);
  const [insights,      setInsights]      = useState({observations:[],commitments:[]});
  const [error,         setError]         = useState(null);
  const [quickReplies,  setQuickReplies]  = useState([]);
  const [forteData,     setForteData]     = useState(null);
  const [showForteUpload, setShowForteUpload] = useState(false);
  const scrollRef = useRef(null);
  const legacyRef = useRef("");
  const catalystRef = useRef("");
  const sendingRef = useRef(false);
  const levelInfo = LEVEL_DATA[level] || LEVEL_DATA[1];

  const addMsg = useCallback((role,text,artifact=null)=>{
    if(role==="coach" && text && text.length > 0) {
      // Stream coach text word by word
      const id = Date.now()+Math.random();
      setMessages(prev=>[...prev,{id,role,text:"",artifact,streaming:true}]);
      const words = text.split(" ");
      let i = 0;
      const interval = setInterval(()=>{
        i++;
        setMessages(prev=>prev.map(m=>m.id===id ? {...m, text:words.slice(0,i).join(" ")} : m));
        if(i>=words.length){
          clearInterval(interval);
          setMessages(prev=>prev.map(m=>m.id===id ? {...m, streaming:false} : m));
        }
      }, 28);
    } else {
      setMessages(prev=>[...prev,{id:Date.now()+Math.random(),role,text,artifact}]);
    }
  },[]);

  useEffect(()=>{
    setTimeout(()=>scrollRef.current?.scrollIntoView({behavior:"smooth"}),60);
  },[messages,typing]);

  useEffect(()=>{
    if(savedState?.messages?.length){
      setMessages(savedState.messages);
      if(savedState.legacy){setLegacy(savedState.legacy);legacyRef.current=savedState.legacy;}
      if(savedState.catalyst){setCatalyst(savedState.catalyst);catalystRef.current=savedState.catalyst;}
      if(savedState.currentModule) setCurrentModule(savedState.currentModule);
      if(savedState.insights) setInsights(savedState.insights);
      if(savedState.forteData) setForteData(savedState.forteData);
    } else {
      // Generate personalized opening via API using name and level
      const timer = setTimeout(async ()=>{
        setTyping(true);
        const levelInfo = LEVEL_DATA[level] || LEVEL_DATA[1];
        const name = participantName || "there";
        const openingPrompt = `This is the very first message of the session. The participant's name is ${name} and they are a ${levelInfo.name}. Welcome them warmly and personally by name. Use the level-appropriate opening style from your instructions. Then ask the peak performance opening question. Keep it to 3-4 sentences max. Do not explain what the program is -- just open with warmth and go straight into the first question.`;
        try {
          const res = await fetch("/api/chat", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              model: "claude-sonnet-4-20250514",
              max_tokens: 300,
              system: buildSystemPrompt({
                participantName: name,
                levelName: levelInfo.name,
                levelCoaching: levelInfo.coaching,
                legacy: "",
                catalyst: "",
                forteData: "Not yet uploaded",
                currentModule: 1,
              }),
              messages: [{ role: "user", content: openingPrompt }]
            })
          });
          const json = await res.json();
          const aiText = json.content?.[0]?.text;
          setTyping(false);
          if(aiText) {
            const { text:cleanText } = parseAIResponse(aiText);
            addMsg("coach", cleanText);
          } else {
            addMsg("coach", "Hey " + name + " -- welcome. Before we dive into anything, I want to start with one question. Think of a moment recently when you were completely on your game in a conversation. What made that work?");
          }
        } catch(err) {
          setTyping(false);
          addMsg("coach", "Hey " + name + " -- welcome. Before we dive into anything, I want to start with one question. Think of a moment recently when you were completely on your game in a conversation. What made that work?");
        }
      }, 700);
      return ()=>clearTimeout(timer);
    }
  },[]);

  useEffect(()=>{
    if(!messages.length) return;
    onSave?.({messages,legacy,catalyst,currentModule,insights,forteData});
  },[messages,legacy,catalyst,currentModule,insights,forteData]);

  const handleSend = useCallback(async(text)=>{
    if(!text.trim()||sendingRef.current) return;
    sendingRef.current = true;
    setQuickReplies([]);
    setError(null);
    addMsg("user",text);
    setInput("");
    // Brief "reading" pause before typing indicator -- feels more human
    await new Promise(r=>setTimeout(r, 400 + Math.random()*600));
    setTyping(true);

    const history = [...messages,{role:"user",text}].filter(m=>m.text&&m.text.trim());
    let apiMessages = history.map(m=>({role:m.role==="coach"?"assistant":"user",content:(m.text||"").trim()})).filter(m=>m.content);
    while(apiMessages.length>0&&apiMessages[0].role==="assistant") apiMessages.shift();
    const collapsed = [];
    for(const msg of apiMessages){
      if(collapsed.length>0&&collapsed[collapsed.length-1].role===msg.role){
        collapsed[collapsed.length-1].content += "\n" + msg.content;
      } else { collapsed.push({...msg}); }
    }

    const profile = {
      levelName: levelInfo.name,
      levelCoaching: levelInfo.coaching,
      participantName: participantName || "the participant",
      legacy: legacyRef.current,
      catalyst: catalystRef.current,
      forteData: forteData ? "Primary Profile -- Dom:" + forteData.green.scores[0] + ", Ext:" + forteData.green.scores[1] + ", Pat:" + forteData.green.scores[2] + ", Con:" + forteData.green.scores[3] : "Not yet uploaded",
      currentModule,
    };

    try {
      if(collapsed.length===0) throw new Error("No messages to send");
      const systemPrompt = buildSystemPrompt(profile);

      const res = await fetch("/api/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          system: systemPrompt,
          messages: collapsed
        })
      });

      const json = await res.json();
      if (!res.ok) throw new Error(json.error || "API error " + res.status);
      const aiText = json.content?.[0]?.text;
      if (!aiText) throw new Error("No response from coach");

      const {text:cleanText, artifacts} = parseAIResponse(aiText);
      setTyping(false);

      artifacts.forEach(a=>{
        if(a.type==="capture_legacy"){ 
          legacyRef.current=a.value; setLegacy(a.value); setPanelDot(true);
          setTimeout(()=>addMsg("coach","",{type:"legacy", text:a.value}),400);
          // Don't auto-trigger Forte upload -- coach will drive that naturally
        }
        if(a.type==="capture_catalyst"){ catalystRef.current=a.value; setCatalyst(a.value); setPanelDot(true); }
        if(a.type==="show_forte_upload"){ 
          // Show the Forte entry screen after a brief delay so the coach message renders first
          setTimeout(()=>setShowForteUpload(true),1800); 
        }
        if(a.type==="module_advance"){ setCurrentModule(a.n); }
        if(a.type==="coach_insight"){ setInsights(prev=>({...prev,observations:[...prev.observations,a.value]})); setPanelDot(true); }
        if(a.type==="show_switches_knobs"){ setTimeout(()=>addMsg("coach","",{type:"switches_knobs"}),400); }
        if(a.type==="show_generations"){ setTimeout(()=>addMsg("coach","",{type:"gencard"}),400); }
        if(a.type==="show_listening_tendencies"){ setTimeout(()=>addMsg("coach","",{type:"listening_tendencies"}),400); }
        if(a.type==="show_crisis_challenge"){ setTimeout(()=>addMsg("coach","",{type:"crisis_challenge"}),400); }
        if(a.type==="show_proficiency_rating"){ setTimeout(()=>addMsg("coach","",{type:"proficiency_rating",topic:a.topic}),400); }
        if(a.type==="show_adapt_planner"){ setTimeout(()=>addMsg("coach","",{type:"adapt_planner"}),400); }
      });

      if(cleanText) addMsg("coach",cleanText);

    } catch(err) {
      setError("Coach error: " + (err.message||"unknown error"));
    } finally {
      setTyping(false);
      sendingRef.current = false;
    }
  },[messages,levelInfo,currentModule,forteData,addMsg]);

  const renderArtifact = (a) => {
    if(!a) return null;
    if(a.type==="milestone") return <MilestoneCard n={a.n} title={a.title||""} sub={a.sub||""} />;
    if(a.type==="legacy")    return <LegacyCard text={a.text||legacy} />;
    if(a.type==="forte")     return <ForteGraph forteData={forteData} />;
    if(a.type==="gap")       return <GapAlert />;
    if(a.type==="gencard")   return <GenCardArtifact onCoachTalk={card=>handleSend("Tell me about the " + card.g + " scenario")} />;
    if(a.type==="crisis_challenge") return <CrisisChallenge onCoachTalk={(responses,strategy)=>handleSend("I just completed the Crisis Navigation Challenge. Here are my responses: " + responses.map((r,i)=>"Q"+(i+1)+": "+r.a).join(". ") + " What do you think?")} />;
    if(a.type==="switches_knobs") return <SwitchesKnobsArtifact catalyst={catalyst} onCoachTalk={(item,t)=>handleSend("Let us talk about the " + item.label + " " + t + " for my Catalyst")} />;
    if(a.type==="listening_tendencies") return <ListeningTendenciesArtifact forteData={forteData} onCoachTalk={(style,item)=>handleSend("Let us talk about my " + style + " listening tendency")} />;
    if(a.type==="proficiency_rating") return <ProficiencyRating topic={a.topic||"Bringing Your Best"} onComplete={(topic,level)=>handleSend("I rated myself as " + level + " on " + topic + ". Let us discuss what that means.")} />;
    if(a.type==="adapt_planner") return <ADAPTPlanner catalyst={catalyst} onComplete={vals=>handleSend("Here is my ADAPT plan: Analyze: " + vals.analyze + " | Describe: " + vals.describe + " | Acknowledge: " + vals.acknowledge + " | Pivot: " + vals.pivot + " | Track: " + vals.track)} />;
    return null;
  };

  return (
    <div style={{flex:1,background:C.navy,display:"flex",flexDirection:"column",position:"relative",overflow:"hidden"}}>
      <div style={{background:C.navy,padding:"14px 18px",display:"flex",alignItems:"center",gap:12,flexShrink:0,boxShadow:"0 2px 12px rgba(0,0,0,.2)"}}>
        <div style={{width:44,height:44,borderRadius:12,background:C.gold,display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden",flexShrink:0}}>
          <Logo size={30} />
        </div>
        <div style={{flex:1}}>
          <div style={{fontSize:16,fontWeight:800,color:C.white}}>CQ Coach</div>
          <div style={{fontSize:12,color:"rgba(255,255,255,.55)",marginTop:2,display:"flex",alignItems:"center",gap:5}}>
            <div style={{width:7,height:7,borderRadius:"50%",background:"#4cd96b",flexShrink:0}} />
            Session 1 - Private and secure
          </div>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          <button onClick={()=>{setPanelOpen(true);setPanelDot(false);}} style={{background:"rgba(255,255,255,.15)",border:"1.5px solid rgba(255,255,255,.25)",borderRadius:20,padding:"7px 14px",display:"flex",alignItems:"center",gap:5,cursor:"pointer",flexShrink:0,position:"relative"}}>
            <span style={{fontSize:12,fontWeight:800,color:C.white}}>My CQ</span>
            {panelDot&&<div style={{width:7,height:7,borderRadius:"50%",background:C.gold}} />}
          </button>
          <button onClick={()=>{if(window.confirm("Start a new session? Your current progress will be cleared."))onReset?.();}} style={{background:"rgba(255,255,255,.1)",border:"1.5px solid rgba(255,255,255,.15)",borderRadius:"50%",width:34,height:34,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",flexShrink:0}}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="rgba(255,255,255,.6)" strokeWidth="2.2" strokeLinecap="round"><path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"/><path d="M3 3v5h5"/></svg>
          </button>
          <button onClick={()=>onReset?.()} title="Exit session" style={{background:"rgba(255,255,255,.07)",border:"1px solid rgba(255,255,255,.12)",borderRadius:8,padding:"6px 10px",cursor:"pointer",fontSize:11,fontWeight:700,color:"rgba(255,255,255,.4)"}}>✕</button>
        </div>
      </div>

      <JourneyTracker currentModule={currentModule} open={journeyOpen} onToggle={()=>setJourneyOpen(o=>!o)} />

      <div style={{flex:1,overflowY:"auto",padding:"0 0 12px",display:"flex",flexDirection:"column",background:C.cream}}>
        <div style={{textAlign:"center",padding:"18px 0 12px",fontSize:11,fontWeight:700,letterSpacing:".12em",textTransform:"uppercase",color:"rgba(36,65,105,.4)"}}>FIRST SESSION -- TODAY</div>
        {messages.map(msg=>(
          <div key={msg.id}>
            {msg.role==="coach"&&msg.text&&<Bubble role="coach" text={msg.text} />}
            {msg.role==="user"&&<Bubble role="user" text={msg.text} />}
            {msg.artifact&&renderArtifact(msg.artifact)}
          </div>
        ))}
        {typing&&<TypingIndicator />}
        {error&&<ErrorBanner msg={error} onDismiss={()=>setError(null)} />}
        {quickReplies.length>0&&<QuickReplies opts={quickReplies} onSelect={opt=>{setQuickReplies([]);handleSend(opt);}} />}
        <div ref={scrollRef} />
      </div>

      <div style={{padding:"10px 12px 22px",background:C.white,borderTop:"1px solid rgba(36,65,105,.08)",flexShrink:0,display:"flex",gap:8,alignItems:"flex-end",boxShadow:"0 -2px 12px rgba(0,0,0,.04)"}}>
        <MicButton onTranscript={setInput} />
        <input value={input} onChange={e=>setInput(e.target.value)}
          onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();handleSend(input);}}}
          placeholder="Type or use mic..."
          style={{flex:1,background:C.white,border:"1.5px solid rgba(36,65,105,.15)",borderRadius:20,padding:"10px 15px",color:C.navy,fontSize:15,outline:"none",fontFamily:"inherit",lineHeight:1.4}} />
        <button onClick={()=>handleSend(input)} disabled={typing} style={{height:46,padding:"0 18px",borderRadius:23,background:typing?"rgba(36,65,105,.4)":C.navy,border:"none",cursor:typing?"not-allowed":"pointer",fontSize:13,fontWeight:800,color:C.white,whiteSpace:"nowrap"}}>Send</button>
      </div>

      <MyCQPanel open={panelOpen} onClose={()=>setPanelOpen(false)} legacy={legacy} catalyst={catalyst} insights={insights} currentModule={currentModule} />
      {showForteUpload && (
        <ForteUploadScreen
          onComplete={(fd)=>{
            setForteData(fd); setShowForteUpload(false);
            setTimeout(()=>addMsg("coach","",{type:"forte"}),200);
            setTimeout(()=>{
              setTyping(true);
              setTimeout(()=>{ setTyping(false); addMsg("coach","Got it -- I can see your full profile now. Before I walk you through what I see, I want to hear from you first. When you looked at your results -- what was your first reaction?"); },1000);
            },500);
          }}
          onSkip={()=>{ setShowForteUpload(false); addMsg("coach","No problem -- you can upload it any time from the My CQ panel. Let us keep going."); }}
        />
      )}
    </div>
  );
};

export default function App() {
  const [screen,         setScreen]       = useState("home");
  const [level,          setLevel]         = useState(null);
  const [participantName,setParticipantName]= useState("");
  // intro screen shows between level select and coach
  const [restored,       setRestored]      = useState(false);
  const [savedState,     setSavedState]    = useState(null);

  useEffect(()=>{
    loadSession().then(s=>{
      if(s?.screen==="coach"&&s?.messages?.length>0){setScreen("coach");setLevel(s.level||null);setParticipantName(s.participantName||"");setSavedState(s);}
      setRestored(true);
    });
  },[]);

  const handleReset = async()=>{await clearSession();setScreen("home");setLevel(null);setParticipantName("");setSavedState(null);};

  if(!restored) return <div style={{display:"flex",alignItems:"center",justifyContent:"center",minHeight:"100vh",background:"#1c1c2e"}}><style>{STYLES}</style><div style={{width:36,height:36,border:"3px solid rgba(244,188,45,.2)",borderTopColor:C.gold,borderRadius:"50%",animation:"spin .8s linear infinite"}} /></div>;

  return (
    <>
      <style>{STYLES}</style>
      <div style={{display:"flex",alignItems:"center",justifyContent:"center",minHeight:"100vh",background:"#1c1c2e",padding:16,fontFamily:"-apple-system,'Segoe UI','Helvetica Neue',Arial,sans-serif"}}>
        <div style={{width:390,height:844,borderRadius:52,overflow:"hidden",display:"flex",flexDirection:"column",position:"relative",boxShadow:"0 0 0 10px #2a2a3e, 0 0 0 11.5px rgba(255,255,255,.07), 0 50px 100px rgba(0,0,0,.7)"}}>
          <div style={{padding:"14px 26px 0",display:"flex",justifyContent:"space-between",alignItems:"center",flexShrink:0,background:screen==="home"||screen==="level"?C.gold:C.navy,color:screen==="home"||screen==="level"?C.navy:"rgba(255,255,255,.9)"}}>
            <span style={{fontSize:15,fontWeight:700}}>{new Date().toLocaleTimeString("en-US",{hour:"numeric",minute:"2-digit"})}</span>
            <div style={{display:"flex",alignItems:"center",gap:5,opacity:.7}}>
              <svg width="16" height="12" viewBox="0 0 16 12" fill="none"><path d="M8 9.5a1 1 0 1 1 0 2 1 1 0 0 1 0-2z" fill="currentColor"/><path d="M5.2 7.3a4 4 0 0 1 5.6 0" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/><path d="M2.5 4.7A7.5 7.5 0 0 1 13.5 4.7" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/></svg>
              <div style={{width:22,height:11,border:"1.5px solid currentColor",borderRadius:3,position:"relative"}}><div style={{position:"absolute",left:2,top:2,width:13,height:5,background:"currentColor",borderRadius:1}} /></div>
            </div>
          </div>
          {screen==="home"  && <HomeScreen  onStart={s=>{const next=s==="level"?"level":"coach";setScreen(next);}} />}
          {screen==="level" && <LevelScreen onSelect={(l,n)=>{setLevel(l);setParticipantName(n);setScreen("intro");}} onBack={()=>setScreen("home")} />}
          {screen==="intro" && <CQIntroScreen participantName={participantName} level={level} onContinue={()=>setScreen("coach")} onBack={()=>setScreen("level")} />}
          {screen==="coach" && <CoachScreen level={level} participantName={participantName} savedState={savedState} onSave={s=>saveSession({screen:"coach",level,participantName,...s})} onReset={handleReset} />}
        </div>
      </div>
    </>
  );
}
